sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}

	//HT - STRY0052942
	//This script uses the addDays function from Script Include MyDateTimeAjax to add default days to the suspense date based on the task type
	var taskerType = g_form.getDisplayValue('tasker_type');

	if(taskerType != undefined && taskerType ==  'Acknowledgement'){		
		var ajax = new GlideAjax('MyDateTimeAjax');
		ajax.addParam('sysparm_name', 'addDaysAcknowledgementSuspenseDate');

		ajax.getXML(function(response){
			var answer = response.responseXML.documentElement.getAttribute("answer");
			if(answer){
				var jsonAnswer = JSON.parse(answer);
				var daysAdded = jsonAnswer.days_from_today;
				g_form.setValue('suspense_date', daysAdded);
			}
			return;
		});
	}
}
